# apply-theme2.ps1 - dark-theme cleanup for Debts tree, Documents, and Admin
# Run from App B repo root (paycheck-planner-UPDATED\paycheck-planner).
$ErrorActionPreference = "Stop"
if (-not (Test-Path "package.json") -or -not (Test-Path "app")) {
  Write-Host "ERROR: run from the repo root (folder with package.json)." -ForegroundColor Red; exit 1 }
$files = @{}
$files['app\debts\page.tsx'] = ''
$files['app\components\DebtFreedomCountdown.tsx'] = ''
$files['app\components\NetWorthTracker.tsx'] = ''
$files['app\components\PaycheckPlanner.tsx'] = ''
$files['app\components\PaycheckBreakdownChart.tsx'] = ''
$files['app\components\BudgetShockDetector.tsx'] = ''
$files['app\components\InterestLeakDetector.tsx'] = ''
$files['app\components\DebtProgress.tsx'] = ''
$files['app\components\DebtTable.tsx'] = ''
$files['app\documents\page.tsx'] = ''
$files['app\components\DocumentCapture.tsx'] = ''
$files['app\admin\page.tsx'] = ''
foreach ($rel in $files.Keys) {
  $full = Join-Path $PWD $rel
  $dir = Split-Path $full -Parent
  if (-not (Test-Path $dir)) { New-Item -ItemType Directory -Force -Path $dir | Out-Null }
  [System.IO.File]::WriteAllBytes($full, [Convert]::FromBase64String($files[$rel]))
  Write-Host "  wrote $rel" -ForegroundColor Green }
Write-Host "Done. 12 files written." -ForegroundColor Cyan